mapper.select:
SELECT m.id, m.tomb_id, t.name AS tomb_name, m.visitor_name, m.avatar, m.content, m.status, m.reject_reason, m.create_time, (CASE WHEN #{param.isAdmin} = true THEN 'admin' WHEN t.family_id IS NOT NULL AND EXISTS (SELECT 1 FROM family_admin fa WHERE fa.family_id = COALESCE(fam.root_id, fam.id) AND fa.user_id = #{param.currentUserId} AND fa.role IN ('super_admin','admin')) THEN 'admin' WHEN t.family_id IS NOT NULL AND fam.chief_id = #{param.currentUserId} THEN 'chief' WHEN t.family_id IS NOT NULL AND (fam.founder_id = #{param.currentUserId} OR EXISTS (SELECT 1 FROM family_member fm WHERE fm.family_id = fam.id AND fm.user_id = #{param.currentUserId} AND fm.del_flag = 0)) THEN 'member' WHEN t.family_id IS NULL AND (t.user_id = #{param.currentUserId} OR t.create_by = #{param.currentUserId}) THEN 'member' ELSE NULL END) AS myRole FROM tomb_message m LEFT JOIN tomb t ON m.tomb_id = t.id AND t.del_flag = 0 LEFT JOIN family fam ON t.family_id = fam.id AND fam.del_flag = 0
AND (m.content LIKE CONCAT('%', #{param.keyword, jdbcType=VARCHAR}, '%') OR t.name LIKE CONCAT('%', #{param.keyword, jdbcType=VARCHAR}, '%'))
AND ( m.status = #{param.status}
OR m.user_id = #{param.currentUserId}
)
AND m.tomb_id = #{param.tombId}
AND t.family_id IN ( WITH RECURSIVE fid AS ( SELECT id FROM family WHERE id = #{param.familyId} AND del_flag = 0 UNION ALL SELECT f.id FROM family f INNER JOIN fid ON f.pid = fid.id WHERE f.del_flag = 0 ) SELECT id FROM fid )
AND ((t.family_id IS NOT NULL AND (SELECT COALESCE(f.root_id, f.id) FROM family f WHERE f.id = t.family_id AND f.del_flag = 0 LIMIT 1) IN ( SELECT DISTINCT COALESCE(f2.root_id, f2.id) FROM family f2 WHERE f2.del_flag = 0 AND (f2.founder_id = #{param.currentUserId} OR f2.id IN (SELECT family_id FROM family_member WHERE user_id = #{param.currentUserId} AND del_flag = 0) OR COALESCE(f2.root_id, f2.id) IN (SELECT family_id FROM family_admin WHERE user_id = #{param.currentUserId})) )) OR (t.family_id IS NULL AND (t.user_id = #{param.currentUserId} OR t.create_by = #{param.currentUserId})))
AND m.del_flag = 0
ORDER BY m.id DESC
